<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Discovery</title>
<style>
  body { font-family: monospace; background: #111; color: #eee; text-align: center; }
  #maze { display: inline-block; background: #000; margin: 10px; border: 2px solid #444; }
  #info { margin: 10px; }
  button { font-family: monospace; padding: 6px 12px; cursor: pointer; }
  .stat { margin: 0 10px; }
</style>
</head>
<body>
<h2>Bot Maze Discovery</h2>
<div id="info">
  <span class="stat">Completed: <span id="completed">0</span>/24</span>
  <span class="stat">Timer: <span id="timer">0</span></span>
  <button id="reset">Reset</button>
</div>
<canvas id="maze" width="480" height="480"></canvas>

<script>
(function(){
  const ROWS = 17, COLS = 17;
  const N_BOTS = 24;
  const CELL = Math.floor(480 / Math.max(ROWS, COLS));
  const CANVAS = document.getElementById('maze');
  const CTX = CANVAS.getContext('2d');
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  // ---- PRNG ----
  function mulberry32(a){
    return function(){
      a |= 0; a = a + 0x6D2B79F5 | 0;
      let t = Math.imul(a ^ a >>> 15, 1 | a);
      t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
      return ((t ^ t >>> 14) >>> 0) / 4294967296;
    };
  }

  // ---- Maze generation (recursive backtracker) ----
  function genMaze(seed){
    const rng = mulberry32(seed);
    const grid = [];
    for(let r=0;r<ROWS;r++){
      grid[r]=[];
      for(let c=0;c<COLS;c++){
        grid[r][c]={n:true,e:true,s:true,w:true,visited:false};
      }
    }
    const stack=[];
    let r=0,c=0;
    grid[r][c].visited=true;
    stack.push([r,c]);
    const dirs=[['n',-1,0],['e',0,1],['s',1,0],['w',0,-1]];
    while(stack.length){
      const [cr,cc]=stack[stack.length-1];
      const opts=[];
      for(const [d,dr,dc] of dirs){
        const nr=cr+dr,nc=cc+dc;
        if(nr>=0&&nr<ROWS&&nc>=0&&nc<COLS&&!grid[nr][nc].visited) opts.push([d,dr,dc,nr,nc]);
      }
      if(opts.length){
        const [d,dr,dc,nr,nc]=opts[Math.floor(rng()*opts.length)];
        grid[cr][cc][d]=false;
        grid[nr][nc][{n:'s',e:'w',s:'n',w:'e'}[d]]=false;
        grid[nr][nc].visited=true;
        stack.push([nr,nc]);
      } else {
        stack.pop();
      }
    }
    return grid;
  }

  // ---- Game state ----
  let state = null;

  function makeBot(i, spawn, exit, rng){
    const order = ['n','e','s','w'];
    // shuffle by seed
    for(let k=order.length-1;k>0;k--){
      const j=Math.floor(rng()*(k+1));
      [order[k],order[j]]=[order[j],order[k]];
    }
    return {
      id:i,
      r:spawn.r, c:spawn.c,
      path:[{r:spawn.r,c:spawn.c}],
      deadEnds:[],
      visited:{}, // key r,c -> count of entries
      finishTick:null,
      order,
      backtracking:false,
      prev:null,
      animFrom:{r:spawn.r,c:spawn.c},
      animTo:{r:spawn.r,c:spawn.c},
      animT:1
    };
  }

  function reset(seed){
    if(seed===undefined) seed = Math.floor(Math.random()*1e9);
    const rng = mulberry32(seed);
    const grid = genMaze(seed);
    const spawn = {r:0,c:0};
    const exit = {r:ROWS-1,c:COLS-1};
    const bots = [];
    for(let i=0;i<N_BOTS;i++){
      bots.push(makeBot(i, spawn, exit, mulberry32(seed*97+i*131+7)));
    }
    state = {
      seed, grid, spawn, exit, bots,
      elapsed:0,
      done:false,
      completedCount:0
    };
    draw();
    updateUI();
  }

  function key(r,c){ return r+','+c; }

  function opposite(d){
    return {n:'s',s:'n',e:'w',w:'e'}[d];
  }
  function delta(d){
    return {n:[-1,0],s:[1,0],e:[0,1],w:[0,-1]}[d];
  }

  // Bot step logic (Tremaux-like)
  function botStep(bot){
    if(bot.finishTick!==null) return;
    const {grid}=state;
    const cell = grid[bot.r][bot.c];
    // mark visited
    const k = key(bot.r,bot.c);
    bot.visited[k] = (bot.visited[k]||0)+1;

    // exit?
    if(bot.r===state.exit.r && bot.c===state.exit.c){
      bot.finishTick = state.elapsed+1;
      return;
    }

    // determine available directions (no wall)
    const avail = [];
    for(const d of ['n','e','s','w']){
      if(!cell[d]) avail.push(d);
    }

    // count how many times we've entered neighbors
    const neighborCounts = {};
    for(const d of avail){
      const [dr,dc]=delta(d);
      const nr=bot.r+dr, nc=bot.c+dc;
      neighborCounts[d] = bot.visited[key(nr,nc)]||0;
    }

    let chosen=null;
    if(!bot.backtracking){
      // prefer unvisited
      const unvisited = avail.filter(d=>neighborCounts[d]===0);
      if(unvisited.length){
        // pick by preference order
        for(const d of bot.order){
          if(unvisited.includes(d)){ chosen=d; break; }
        }
      } else {
        // all visited -> dead end / fully explored branch -> backtrack
        bot.backtracking=true;
        bot.deadEnds.push({r:bot.r,c:bot.c});
      }
    }

    if(bot.backtracking){
      // go back to previous cell (prev direction)
      if(bot.prev){
        chosen = opposite(bot.prev);
        // if that wall exists (shouldn't), fallback
        if(cell[chosen]){
          // pick any available that is not increasing? just pick least visited
          let best=null,bv=1e9;
          for(const d of avail){
            if(neighborCounts[d]<bv){bv=neighborCounts[d];best=d;}
          }
          chosen=best;
        }
      } else {
        // at spawn, nowhere to backtrack: pick least visited
        let best=null,bv=1e9;
        for(const d of avail){
          if(neighborCounts[d]<bv){bv=neighborCounts[d];best=d;}
        }
        chosen=best;
        bot.backtracking=false;
      }
      // stop backtracking if we reach a cell with unvisited neighbor
      const [dr,dc]=delta(chosen);
      const nr=bot.r+dr,nc=bot.c+dc;
      if((bot.visited[key(nr,nc)]||0)===0) bot.backtracking=false;
    }

    if(chosen===null){
      // fallback (shouldn't happen): stay
      bot.animFrom={r:bot.r,c:bot.c};
      bot.animTo={r:bot.r,c:bot.c};
      bot.animT=1;
      return;
    }

    const [dr,dc]=delta(chosen);
    const nr=bot.r+dr, nc=bot.c+dc;
    bot.prev = chosen;
    bot.animFrom={r:bot.r,c:bot.c};
    bot.animTo={r:nr,c:nc};
    bot.animT=0;
    bot.r=nr; bot.c=nc;
    bot.path.push({r:nr,c:nc});
  }

  function tick(n){
    if(!state) return;
    for(let i=0;i<n;i++){
      if(state.done) break;
      state.elapsed++;
      for(const bot of state.bots){
        if(bot.finishTick===null) botStep(bot);
      }
      // advance animation
      for(const bot of state.bots){
        if(bot.animT<1) bot.animT=Math.min(1,bot.animT+1);
      }
      // check completion
      let allDone=true;
      let cnt=0;
      for(const bot of state.bots){
        if(bot.finishTick!==null) cnt++;
        else allDone=false;
      }
      state.completedCount=cnt;
      if(allDone){
        state.done=true;
        break;
      }
    }
    draw();
    updateUI();
  }

  function updateUI(){
    completedEl.textContent = state.completedCount;
    timerEl.textContent = state.elapsed;
  }

  function draw(){
    CTX.clearRect(0,0,CANVAS.width,CANVAS.height);
    // walls
    CTX.strokeStyle='#0af';
    CTX.lineWidth=2;
    for(let r=0;r<ROWS;r++){
      for(let c=0;c<COLS;c++){
        const x=c*CELL, y=r*CELL;
        const cell=state.grid[r][c];
        if(cell.n){ CTX.beginPath(); CTX.moveTo(x,y); CTX.lineTo(x+CELL,y); CTX.stroke(); }
        if(cell.w){ CTX.beginPath(); CTX.moveTo(x,y); CTX.lineTo(x,y+CELL); CTX.stroke(); }
        if(cell.e){ CTX.beginPath(); CTX.moveTo(x+CELL,y); CTX.lineTo(x+CELL,y+CELL); CTX.stroke(); }
        if(cell.s){ CTX.beginPath(); CTX.moveTo(x,y+CELL); CTX.lineTo(x+CELL,y+CELL); CTX.stroke(); }
      }
    }
    // spawn & exit
    CTX.fillStyle='#2f2';
    CTX.fillRect(state.spawn.c*CELL+CELL/4, state.spawn.r*CELL+CELL/4, CELL/2, CELL/2);
    CTX.fillStyle='#f22';
    CTX.fillRect(state.exit.c*CELL+CELL/4, state.exit.r*CELL+CELL/4, CELL/2, CELL/2);
    // bots
    for(let i=0;i<state.bots.length;i++){
      const bot=state.bots[i];
      const t=bot.animT;
      const fr=bot.animFrom.r+(bot.animTo.r-bot.animFrom.r)*t;
      const fc=bot.animFrom.c+(bot.animTo.c-bot.animFrom.c)*t;
      const x=fc*CELL+CELL/2;
      const y=fr*CELL+CELL/2;
      CTX.beginPath();
      CTX.fillStyle=`hsl(${(i*360/N_BOTS)},80%,60%)`;
      CTX.arc(x,y,CELL/4,0,Math.PI*2);
      CTX.fill();
    }
  }

  // ---- Public API ----
  window.game = {
    tick: function(n){ tick(n||1); },
    reset: function(seed){ reset(seed); },
    get elapsed(){ return state.elapsed; },
    get size(){ return {rows:ROWS, cols:COLS}; },
    get spawn(){ return {r:state.spawn.r, c:state.spawn.c}; },
    get exit(){ return {r:state.exit.r, c:state.exit.c}; },
    walls: function(r,c){ const cell=state.grid[r][c]; return {n:cell.n,e:cell.e,s:cell.s,w:cell.w}; },
    get bots(){ return state.bots.map(b=>({
        path:b.path.map(p=>({r:p.r,c:p.c})),
        deadEnds:b.deadEnds.map(p=>({r:p.r,c:p.c})),
        finishTick:b.finishTick
      })); }
  };

  resetBtn.addEventListener('click', ()=>reset());
  reset();
})();
</script>
</body>
</html>
